            long long k = nums[i] & nums[j];
            can_swap[k].push_back(i);
            can_swap[k].push_back(j);
        }
    }

    // Try each possible k in descending order
    for (long long k = INT_MAX; k >= 0; --k) {
        // Check if k is possible to swap to sort the array
        std::vector<bool> visited(n, false);
        bool can_sort = true;

        for (int i = 0; i < n; ++i) {
            if (visited[i]) continue;
